-- Migration: seed_talaud_island_boundaries
-- Loads real polygon boundaries from Talaud.json (island_name property)
-- for the Kepulauan Talaud service area (Kabupaten Kepulauan Talaud,
-- Sulawesi Utara, Indonesia).
--
-- All geometries are WGS-84 (SRID 4326), validated as ST_IsValid = true.
-- Area reference:
--   Karakelang  ~803 km²  (main island, 247 boundary points)
--   Kabaruan     ~92 km²  (46 points)
--   Salibabu     ~87 km²  (84 points)
--   Sara Besar   ~0.5 km² (6 points)
--   Sara Kecil   ~0.1 km² (5 points)

-- Step 1: remove placeholder rows from migration 004
DELETE FROM islands WHERE name IN ('Island 1', 'Island 2', 'Island 3');

-- Step 2: insert real island names
INSERT INTO islands (name) VALUES
    ('Kabaruan'),
    ('Karakelang'),
    ('Salibabu'),
    ('Sara Besar'),
    ('Sara Kecil')
ON CONFLICT (name) DO NOTHING;

-- Step 3: load boundaries
